import path from "node:path";
import { performance } from "node:perf_hooks";
import { electron } from "./electron.js";

const DEV_LOG_RUNTIME_KEY = "__NEXUS_DEV_LOG_RUNTIME__";
const IPC_DEV_LOG_BATCH_CHANNEL = "dev-log:append-batch";
const IPC_DEV_LOG_META_KEY = "__nexusDevLogMeta";

export type DevLogLevel = "debug" | "info" | "warn" | "error" | "fatal";

export type DevLogEvent = {
  ts?: string;
  sessionId?: string | null;
  rendererRunId?: string | null;
  mode?: "dev" | "compiled";
  process?: string;
  surface?: string;
  subsystem?: string;
  level?: DevLogLevel;
  event: string;
  message?: string;
  durationMs?: number | null;
  requestId?: string | null;
  windowId?: number | null;
  pid?: number | null;
  data?: Record<string, unknown> | null;
  shard?: string | null;
  mirrorConsole?: boolean;
};

export type DevLogContext = {
  process: string;
  surface: string;
  subsystem: string;
  shard: string;
};

type DevLogRuntime = {
  DEV_LOG_INTERNAL_MARKER?: symbol;
  devLogRawConsole?: {
    log: (...args: unknown[]) => void;
    info: (...args: unknown[]) => void;
    warn: (...args: unknown[]) => void;
    error: (...args: unknown[]) => void;
  };
  devLogAppendEvent?: (event: DevLogEvent) => void;
  devLogAppendBatch?: (events: DevLogEvent[]) => void;
  devLogFormatArgs?: (args: unknown[]) => string;
  devLogFlushNow?: () => void;
  devLogGetSessionInfo?: () => Record<string, unknown>;
  devLogIsVerboseEnabled?: () => boolean;
  devLogMarkRendererBatchReceived?: (count?: number) => void;
  devLogSerializeUnknown?: (value: unknown) => unknown;
};

type DevLogger = {
  context: DevLogContext;
  debug: (event: string, message: string, data?: Record<string, unknown> | null) => void;
  info: (event: string, message: string, data?: Record<string, unknown> | null) => void;
  warn: (event: string, message: string, data?: Record<string, unknown> | null) => void;
  error: (event: string, message: string, data?: Record<string, unknown> | null) => void;
  fatal: (event: string, message: string, data?: Record<string, unknown> | null) => void;
};

type IpcInvokeMeta = {
  requestId?: string;
  rendererRunId?: string;
  source?: string;
};

declare global {
  var __NEXUS_DEV_LOG_CONSOLE_BRIDGE_INSTALLED__: boolean | undefined;
  var __NEXUS_DEV_LOG_IPC_MAIN_BRIDGE_INSTALLED__: boolean | undefined;
  var __NEXUS_DEV_LOG_IPC_BATCH_REGISTERED__: boolean | undefined;
}

function getDevLogRuntime(): DevLogRuntime | null {
  const runtime = (globalThis as typeof globalThis & {
    [DEV_LOG_RUNTIME_KEY]?: DevLogRuntime;
  })[DEV_LOG_RUNTIME_KEY];

  if (!runtime || typeof runtime !== "object") {
    return null;
  }

  return runtime;
}

function devLogGetRawConsole() {
  const runtime = getDevLogRuntime();
  return runtime?.devLogRawConsole ?? {
    log: console.log.bind(console),
    info: console.info.bind(console),
    warn: console.warn.bind(console),
    error: console.error.bind(console),
  };
}

export function devLogSerializeUnknown(value: unknown) {
  const runtime = getDevLogRuntime();
  return runtime?.devLogSerializeUnknown ? runtime.devLogSerializeUnknown(value) : value;
}

export function devLogFlushNow() {
  getDevLogRuntime()?.devLogFlushNow?.();
}

export function devLogIsVerboseEnabled() {
  return Boolean(getDevLogRuntime()?.devLogIsVerboseEnabled?.());
}

export function devLogGetSessionInfo() {
  return getDevLogRuntime()?.devLogGetSessionInfo?.() ?? null;
}

function devLogResolveScope(scope: string): DevLogContext {
  const normalizedScope = String(scope || "").trim() || "main.runtime";

  if (normalizedScope.startsWith("bootstrap.")) {
    return {
      process: "bootstrap",
      surface: "bootstrap",
      subsystem: normalizedScope,
      shard: "10-bootstrap.jsonl",
    };
  }

  if (normalizedScope.startsWith("main.")) {
    return {
      process: "main",
      surface: "main",
      subsystem: normalizedScope,
      shard: "20-main.jsonl",
    };
  }

  if (normalizedScope.startsWith("backend.preview")) {
    return {
      process: "backend",
      surface: "preview",
      subsystem: normalizedScope,
      shard: "32-preview.jsonl",
    };
  }

  if (normalizedScope.startsWith("backend.plugins")) {
    return {
      process: "backend",
      surface: "plugins",
      subsystem: normalizedScope,
      shard: "33-plugins-backend.jsonl",
    };
  }

  if (normalizedScope.startsWith("backend.vaultRuntime") || normalizedScope.startsWith("backend.filesystem")) {
    return {
      process: "backend",
      surface: "vault-runtime",
      subsystem: normalizedScope,
      shard: "31-vault-runtime.jsonl",
    };
  }

  if (normalizedScope.startsWith("backend.")) {
    return {
      process: "backend",
      surface: "backend",
      subsystem: normalizedScope,
      shard: "30-backend.jsonl",
    };
  }

  if (normalizedScope.startsWith("ipc.")) {
    return {
      process: "main",
      surface: "ipc",
      subsystem: normalizedScope,
      shard: "50-ipc.jsonl",
    };
  }

  if (normalizedScope.startsWith("addon.directoryWatcher")) {
    return {
      process: "addon",
      surface: "directory-watcher",
      subsystem: normalizedScope,
      shard: "60-addons-directory-watcher.jsonl",
    };
  }

  if (normalizedScope.startsWith("addon.safeRecycle")) {
    return {
      process: "addon",
      surface: "safe-recycle",
      subsystem: normalizedScope,
      shard: "61-addons-safe-recycle.jsonl",
    };
  }

  return {
    process: "main",
    surface: "main",
    subsystem: normalizedScope,
    shard: "20-main.jsonl",
  };
}

function devLogNormalizeContext(scopeOrContext: string | DevLogContext): DevLogContext {
  return typeof scopeOrContext === "string" ? devLogResolveScope(scopeOrContext) : scopeOrContext;
}

export function devLogAppend(event: DevLogEvent) {
  const runtime = getDevLogRuntime();
  runtime?.devLogAppendEvent?.(event);
}

export function devLogAppendBatch(events: DevLogEvent[]) {
  const runtime = getDevLogRuntime();
  runtime?.devLogAppendBatch?.(events);
}

function devLogShouldMirrorToConsole(level: DevLogLevel) {
  return level === "warn" || level === "error" || level === "fatal";
}

export function createDevLogger(scopeOrContext: string | DevLogContext): DevLogger {
  const context = devLogNormalizeContext(scopeOrContext);

  const emit = (
    level: DevLogLevel,
    event: string,
    message: string,
    data: Record<string, unknown> | null = null,
  ) => {
    devLogAppend({
      ...context,
      level,
      event,
      message,
      data,
      mirrorConsole: devLogShouldMirrorToConsole(level),
    });
  };

  return {
    context,
    debug: (event, message, data = null) => emit("debug", event, message, data),
    info: (event, message, data = null) => emit("info", event, message, data),
    warn: (event, message, data = null) => emit("warn", event, message, data),
    error: (event, message, data = null) => emit("error", event, message, data),
    fatal: (event, message, data = null) => emit("fatal", event, message, data),
  };
}

export async function measureDevStep<T>(
  scopeOrLogger: string | DevLogger,
  name: string,
  action: () => Promise<T> | T,
  meta: Record<string, unknown> | null = null,
) {
  const logger =
    typeof scopeOrLogger === "string"
      ? createDevLogger(scopeOrLogger)
      : scopeOrLogger;

  const startedAt = performance.now();
  logger.info(`${name}.start`, `Inicio de ${name}.`, meta);

  try {
    const result = await action();
    logger.info(`${name}.done`, `Fin de ${name}.`, {
      ...(meta || {}),
      durationMs: Number((performance.now() - startedAt).toFixed(2)),
    });
    return result;
  } catch (error) {
    logger.error(`${name}.error`, `Error durante ${name}.`, {
      ...(meta || {}),
      durationMs: Number((performance.now() - startedAt).toFixed(2)),
      error: devLogSerializeUnknown(error),
    });
    throw error;
  }
}

function devLogNormalizeSourceFile(rawFilePath: string) {
  if (!rawFilePath) {
    return "";
  }

  const decodePathValue = (value: string) => {
    try {
      return decodeURIComponent(value);
    } catch {
      return value;
    }
  };

  if (rawFilePath.startsWith("file:///")) {
    return path.normalize(decodePathValue(new URL(rawFilePath).pathname).replace(/^\//, ""));
  }

  return path.normalize(decodePathValue(rawFilePath.replace(/^file:\/\//, "")));
}

function devLogInferSourceFromStack() {
  const error = new Error();
  const stack = typeof error.stack === "string" ? error.stack.split("\n").slice(1) : [];

  for (const rawLine of stack) {
    const line = rawLine.trim();
    if (!line || line.includes("src/shared/dev-log") || line.includes("dist/shared/dev-log")) {
      continue;
    }

    const match = line.match(/\(?((?:file:\/\/\/)?[A-Za-z]:[^\s)]+|\/[^\s)]+):(\d+):(\d+)\)?$/);
    if (!match) {
      continue;
    }

    return {
      filePath: devLogNormalizeSourceFile(match[1]),
      line: Number.parseInt(match[2], 10),
      column: Number.parseInt(match[3], 10),
    };
  }

  return {
    filePath: "",
    line: null,
    column: null,
  };
}

function devLogResolveScopeBySourceFile(filePathValue: string) {
  const normalized = devLogNormalizeSourceFile(filePathValue);
  const filePathLower = normalized.toLowerCase();

  if (!filePathLower) {
    return devLogResolveScope("main.runtime");
  }

  if (filePathLower.includes(`electron-bootstrap.cjs`)) {
    return devLogResolveScope("bootstrap.console");
  }

  if (filePathLower.includes(`${path.sep}native${path.sep}directory_watcher${path.sep}`)) {
    return devLogResolveScope("addon.directoryWatcher.console");
  }

  if (filePathLower.includes(`${path.sep}native${path.sep}safe_recycle${path.sep}`)) {
    return devLogResolveScope("addon.safeRecycle.console");
  }

  if (
    filePathLower.includes(`${path.sep}dist${path.sep}plugins${path.sep}`) ||
    filePathLower.includes(`${path.sep}src${path.sep}plugins${path.sep}`)
  ) {
    return devLogResolveScope("backend.plugins.console");
  }

  if (
    filePathLower.includes(`${path.sep}dist${path.sep}backend${path.sep}preview${path.sep}`) ||
    filePathLower.includes(`${path.sep}src${path.sep}backend${path.sep}preview${path.sep}`)
  ) {
    return devLogResolveScope("backend.preview.console");
  }

  if (
    filePathLower.includes(`${path.sep}dist${path.sep}backend${path.sep}vault-runtime${path.sep}`) ||
    filePathLower.includes(`${path.sep}src${path.sep}backend${path.sep}vault-runtime${path.sep}`)
  ) {
    return devLogResolveScope("backend.vaultRuntime.console");
  }

  if (
    filePathLower.includes(`${path.sep}dist${path.sep}backend${path.sep}`) ||
    filePathLower.includes(`${path.sep}src${path.sep}backend${path.sep}`) ||
    filePathLower.includes(`${path.sep}dist${path.sep}internalmodules${path.sep}`) ||
    filePathLower.includes(`${path.sep}src${path.sep}internalmodules${path.sep}`)
  ) {
    return devLogResolveScope("backend.runtime.console");
  }

  return devLogResolveScope("main.runtime.console");
}

export function installDevConsoleBridge() {
  if (globalThis.__NEXUS_DEV_LOG_CONSOLE_BRIDGE_INSTALLED__) {
    return;
  }

  const rawConsole = devLogGetRawConsole();
  const internalMarker = getDevLogRuntime()?.DEV_LOG_INTERNAL_MARKER;

  const bridgeMethod = (
    methodName: "debug" | "log" | "info" | "warn" | "error",
    level: DevLogLevel,
  ) => {
    const rawMethod =
      methodName === "debug" || methodName === "log"
        ? rawConsole.log
        : methodName === "info"
          ? rawConsole.info
          : methodName === "warn"
            ? rawConsole.warn
            : rawConsole.error;

    return (...args: unknown[]) => {
      if ((globalThis as typeof globalThis & { [key: symbol]: boolean })[internalMarker || Symbol.for("noop")]) {
        rawMethod(...args);
        return;
      }

      const source = devLogInferSourceFromStack();
      const logger = createDevLogger(devLogResolveScopeBySourceFile(source.filePath));
      const message = getDevLogRuntime()?.devLogFormatArgs?.(args) ?? args.map((entry) => String(entry)).join(" ");

      try {
        if (internalMarker) {
          (globalThis as typeof globalThis & { [key: symbol]: boolean })[internalMarker] = true;
        }

        logger[level](`console.${methodName}`, message, {
          args: devLogSerializeUnknown(args),
          sourceFile: source.filePath || null,
          sourceLine: source.line,
          sourceColumn: source.column,
        });
      } finally {
        if (internalMarker) {
          delete (globalThis as typeof globalThis & { [key: symbol]: boolean })[internalMarker];
        }
      }

      if ((level === "debug" || level === "info") && devLogIsVerboseEnabled()) {
        rawMethod(...args);
      }
    };
  };

  console.debug = bridgeMethod("debug", "debug");
  console.log = bridgeMethod("log", "info");
  console.info = bridgeMethod("info", "info");
  console.warn = bridgeMethod("warn", "warn");
  console.error = bridgeMethod("error", "error");

  globalThis.__NEXUS_DEV_LOG_CONSOLE_BRIDGE_INSTALLED__ = true;
}

function devLogSummarizeValue(value: unknown, depth = 0): unknown {
  if (depth >= 2) {
    return "[max-depth]";
  }

  if (value instanceof Error) {
    return devLogSerializeUnknown(value);
  }

  if (typeof value === "string") {
    return value.length > 240 ? `${value.slice(0, 240)}...` : value;
  }

  if (Array.isArray(value)) {
    return {
      type: "array",
      length: value.length,
      sample: value.slice(0, 4).map((entry) => devLogSummarizeValue(entry, depth + 1)),
    };
  }

  if (value && typeof value === "object") {
    const objectValue = value as Record<string, unknown>;
    const keys = Object.keys(objectValue);
    const interestingKeys = [
      "id",
      "itemId",
      "parentId",
      "filePath",
      "pluginId",
      "enabled",
      "version",
      "offset",
      "limit",
      "directoryName",
      "developmentMode",
      "key",
      "reason",
    ];

    const summary: Record<string, unknown> = {
      type: "object",
      keys: keys.slice(0, 12),
      keyCount: keys.length,
    };

    for (const key of interestingKeys) {
      if (key in objectValue) {
        summary[key] = devLogSummarizeValue(objectValue[key], depth + 1);
      }
    }

    if ("paths" in objectValue && Array.isArray(objectValue.paths)) {
      summary.pathsCount = objectValue.paths.length;
    }

    return summary;
  }

  return value ?? null;
}

function devLogIsAlwaysLoggedIpcChannel(channel: string) {
  return [
    "create-item",
    "update-item",
    "delete-item",
    "delete-item-permanently",
    "move-item",
    "move-items",
    "import-external-items",
    "trash:restore-item",
    "trash:purge-item",
    "vault:reindex",
  ].includes(channel) ||
    (channel.startsWith("plugins:") && channel !== "plugins:list");
}

const DEV_LOG_NOISY_IPC_CHANNELS = new Set([
  "state:get",
  "booru:get-snapshot",
  "booru:list-resources",
  "booru:list-entities",
  "booru:prime-visible-thumbnails",
]);

function devLogResolveIpcCompletionPolicy(
  channel: string,
  durationMs: number,
  alwaysLog: boolean,
): {
  shouldLog: boolean;
  level: DevLogLevel;
} {
  if (DEV_LOG_NOISY_IPC_CHANNELS.has(channel)) {
    return {
      shouldLog: true,
      level: durationMs >= 1500 ? "info" : "debug",
    };
  }

  if (alwaysLog || durationMs >= 25) {
    return {
      shouldLog: true,
      level: durationMs >= 100 ? "warn" : "info",
    };
  }

  return {
    shouldLog: false,
    level: "debug",
  };
}

function devLogExtractIpcMeta(args: unknown[]) {
  if (!args.length) {
    return {
      cleanedArgs: args,
      meta: null as IpcInvokeMeta | null,
    };
  }

  const lastArg = args[args.length - 1];
  if (
    !lastArg ||
    typeof lastArg !== "object" ||
    Array.isArray(lastArg) ||
    !(IPC_DEV_LOG_META_KEY in (lastArg as Record<string, unknown>))
  ) {
    return {
      cleanedArgs: args,
      meta: null as IpcInvokeMeta | null,
    };
  }

  const cleanedArgs = args.slice(0, -1);
  const meta = (lastArg as Record<string, IpcInvokeMeta>)[IPC_DEV_LOG_META_KEY] ?? null;
  return {
    cleanedArgs,
    meta,
  };
}

export function installDevIpcMainBridge() {
  if (globalThis.__NEXUS_DEV_LOG_IPC_MAIN_BRIDGE_INSTALLED__) {
    return;
  }

  const { ipcMain } = electron;
  const originalHandle = ipcMain.handle.bind(ipcMain);
  const ipcLogger = createDevLogger("ipc.main");

  (ipcMain as typeof ipcMain & { handle: typeof ipcMain.handle }).handle = ((channel, handler) => {
    return originalHandle(channel, async (event, ...rawArgs) => {
      const startedAt = performance.now();
      const { cleanedArgs, meta } = devLogExtractIpcMeta(rawArgs);
      const requestId = meta?.requestId ?? null;
      const payloadSummary = cleanedArgs.map((entry) => devLogSummarizeValue(entry));
      const alwaysLog = devLogIsAlwaysLoggedIpcChannel(channel);

      if (alwaysLog) {
        ipcLogger.info("ipc.invoke.start", `IPC ${channel} iniciado.`, {
          channel,
          requestId,
          payloadSummary,
          senderFrameId: event.frameId,
          senderProcessId: event.processId,
        });
      }

      try {
        const result = await handler(event, ...cleanedArgs);
        const durationMs = Number((performance.now() - startedAt).toFixed(2));
        const completionPolicy = devLogResolveIpcCompletionPolicy(channel, durationMs, alwaysLog);
        if (completionPolicy.shouldLog) {
          ipcLogger[completionPolicy.level]("ipc.invoke.done", `IPC ${channel} completado.`, {
            channel,
            requestId,
            durationMs,
            payloadSummary,
            resultSummary: devLogSummarizeValue(result),
            senderFrameId: event.frameId,
            senderProcessId: event.processId,
          });
        }
        return result;
      } catch (error) {
        ipcLogger.error("ipc.invoke.error", `IPC ${channel} fallo.`, {
          channel,
          requestId,
          durationMs: Number((performance.now() - startedAt).toFixed(2)),
          payloadSummary,
          senderFrameId: event.frameId,
          senderProcessId: event.processId,
          error: devLogSerializeUnknown(error),
        });
        throw error;
      }
    });
  }) as typeof ipcMain.handle;

  globalThis.__NEXUS_DEV_LOG_IPC_MAIN_BRIDGE_INSTALLED__ = true;
}

function devLogResolveRendererFallbackShard(surface?: string, subsystem?: string) {
  if (surface === "startup") {
    return "40-renderer-startup.jsonl";
  }

  if (surface === "store") {
    return "41-renderer-store.jsonl";
  }

  if (surface === "explorer") {
    return "42-renderer-explorer.jsonl";
  }

  if (surface === "editors") {
    return "43-renderer-editors.jsonl";
  }

  if (surface === "plugins") {
    return "44-renderer-plugins.jsonl";
  }

  if (surface === "ipc" || subsystem?.startsWith("renderer.ipc")) {
    return "50-ipc.jsonl";
  }

  return "40-renderer-startup.jsonl";
}

export function registerDevLogIpcBridge() {
  if (globalThis.__NEXUS_DEV_LOG_IPC_BATCH_REGISTERED__) {
    return;
  }

  const { ipcMain, BrowserWindow } = electron;

  ipcMain.on(IPC_DEV_LOG_BATCH_CHANNEL, (event, payload) => {
    const windowId = BrowserWindow.fromWebContents(event.sender)?.id ?? null;
    const pid = event.sender.getOSProcessId?.() ?? null;
    const rawEvents = Array.isArray(payload?.events) ? payload.events : [];

    getDevLogRuntime()?.devLogMarkRendererBatchReceived?.(1);

    const normalizedEvents = rawEvents.map((rawEvent) => {
      const eventValue = rawEvent as DevLogEvent;
      return {
        ...eventValue,
        process: "renderer",
        pid,
        windowId,
        shard: eventValue.shard || devLogResolveRendererFallbackShard(eventValue.surface, eventValue.subsystem),
      } satisfies DevLogEvent;
    });

    devLogAppendBatch(normalizedEvents);
  });

  globalThis.__NEXUS_DEV_LOG_IPC_BATCH_REGISTERED__ = true;
}
