function hasElectronApp(value: unknown): value is typeof import("electron") {
  return Boolean(value && typeof value === "object" && "app" in value);
}

const processElectronMain = (process as typeof process & {
  __electronMain?: typeof import("electron") | { default?: typeof import("electron") };
}).__electronMain;

const globalElectronMain = (globalThis as typeof globalThis & {
  __electronMain?: typeof import("electron") | { default?: typeof import("electron") };
}).__electronMain;

const electronMain =
  (hasElectronApp(processElectronMain) ? processElectronMain : null) ??
  (hasElectronApp(globalElectronMain) ? globalElectronMain : null) ??
  (processElectronMain &&
  typeof processElectronMain === "object" &&
  "default" in processElectronMain &&
  hasElectronApp((processElectronMain as { default?: unknown }).default)
    ? (processElectronMain as { default: typeof import("electron") }).default
    : null) ??
  (globalElectronMain &&
  typeof globalElectronMain === "object" &&
  "default" in globalElectronMain &&
  hasElectronApp((globalElectronMain as { default?: unknown }).default)
    ? (globalElectronMain as { default: typeof import("electron") }).default
    : null);

if (!electronMain) {
  throw new Error("Electron main API no estA disponible en el runtime ESM");
}

export const electron = electronMain;
